import (
	"math"
)

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}

	// Build adjacency list
	adj := make([][]int64, n)
	for _, e := range edges {
		u := e[0]
		v := e[1]
		cost := e[2]
		adj[u] = append(adj[u], int64(v), cost)
	}

	// Compute topological order
	topOrder := computeTopologicalOrder(adj, n)

	// Find max edge cost
	maxEdgeCost := int64(0)
	for _, e := range edges {
		if e[2] > maxEdgeCost {
			maxEdgeCost = e[2]
		}
	}

	// Binary search
	low := 0
	high := maxEdgeCost
	var answer int64 = -1

	for low <= high {
		mid := (low + high) / 2
		if check(mid, topOrder, adj, online, n, k) {
			answer = mid
			low = mid + 1
		} else {
			high = mid - 1
		}
	}

	return answer
}

func computeTopologicalOrder(adj [][]int64, n int) []int {
	inDegree := make([]int, n)
	for u := 0; u < n; u++ {
		for _, edge := range adj[u] {
			v := edge[0]
			inDegree[v]++
		}
	}
	queue := []int{}
	for i := 0; i < n; i++ {
		if inDegree[i] == 0 {
			queue = append(queue, i)
		}
	}
	order := []int{}
	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		order = append(order, u)
		for _, edge := range adj[u] {
			v := edge[0]
			inDegree[v]--
			if inDegree[v] == 0 {
				queue = append(queue, v)
			}
		}
	}
	return order
}

func check(mid int64, topOrder []int, adj [][]int64, online []bool, n int, k int64) bool {
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	dist[0] = 0
	for _, u := range topOrder {
		if !online[u] {
			continue
		}
		for _, edge := range adj[u] {
			v := edge[0]
			cost := edge[1]
			if online[v] && cost >= mid {
				if dist[u]+cost < dist[v] {
					dist[v] = dist[u] + cost
				}
			}
		}
	}
	return dist[n-1] <= k
}
