func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	if n == 0 {
		return -1
	}
	// Build adjacency list
	adj := make([][][2]int64, n)
	for _, edge := range edges {
		u := int(edge[0])
		v := int(edge[1])
		cost := edge[2]
		adj[u] = append(adj[u], [2]int64{v, cost})
	}

	// Compute topological order
	inDegree := make([]int, n)
	for u := 0; u < n; u++ {
		for _, edge := range adj[u] {
			v := edge[0]
			inDegree[v]++
		}
	}
	queue := []int{}
	for i := 0; i < n; i++ {
		if inDegree[i] == 0 {
			queue = append(queue, i)
		}
	}
	topologicalOrder := []int{}
	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		topologicalOrder = append(topologicalOrder, u)
		for _, edge := range adj[u] {
			v := edge[0]
			inDegree[v]--
			if inDegree[v] == 0 {
				queue = append(queue, v)
			}
		}
	}

	// Compute maxEdgeCost
	var maxEdgeCost int64
	for _, edge := range edges {
		if edge[2] > maxEdgeCost {
			maxEdgeCost = edge[2]
		}
	}

	// Binary search
	low := 0
	high := int(maxEdgeCost)
	answer := -1

	for low <= high {
		mid := (low + high) / 2
		// Check if there's a valid path with min edge cost >= mid
		dist := make([]int64, n)
		for i := range dist {
