function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    function computeTopologicalOrder(adj, n) {
        const inDegree = new Array(n).fill(0);
        for (let u = 0; u < n; u++) {
            for (let [v, cost] of adj[u]) {
                inDegree[v]++;
            }
        }
        const queue = [];
        for (let i = 0; i < n; i++) {
            if (inDegree[i] === 0) {
                queue.push(i);
            }
        }
        const order = [];
        while (queue.length > 0) {
            const u = queue.shift();
            order.push(u);
            for (let [v, cost] of adj[u]) {
                inDegree[v]--;
                if (inDegree[v] === 0) {
                    queue.push(v);
                }
            }
        }
        return order;
    }

    const topologicalOrder = computeTopologicalOrder(adj, n);

    const edgeCosts = edges.map(e => e[2]);
    const maxCost = Math.max(...edgeCosts);

    let low = 0, high = maxCost;
    let answer = -1;

    function check(mid) {
        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;
        for (const u of topologicalOrder) {
            if (!online[u]) continue;
            for (const [v, cost] of adj[u]) {
                if (online[v] && cost >= mid) {
                    if (dist[u] + cost < dist[v]) {
                        dist[v] = dist[u] + cost;
                    }
                }
            }
        }
        return dist[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer === -1 ? -1 : answer;
}
