package main

import "math"

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	adj := make([][]int64, n)
	for _, edge := range edges {
		u := edge[0]
		v := edge[1]
		cost := edge[2]
		adj[u] = append(adj[u], []int64{v, cost})
	}

	inDegree := make([]int, n)
	for i := 0; i < n; i++ {
		for _, edge := range adj[i] {
			v := edge[0]
			inDegree[v]++
		}
	}

	queue := []int{}
	for i := 0; i < n; i++ {
		if inDegree[i] == 0 {
			queue = append(queue, i)
		}
	}

	topologicalOrder := []int{}
	for len(queue) > 0 {
		u := queue[0]
		queue = queue[1:]
		topologicalOrder = append(topologicalOrder, u)
		for _, edge := range adj[u] {
			v := edge[0]
			inDegree[v]--
			if inDegree[v] == 0 {
				queue = append(queue, v)
			}
		}
	}

	maxEdgeCost := int64(0)
	for _, edge := range edges {
		if edge[2] > maxEdgeCost {
			maxEdgeCost = edge[2]
		}
	}

	low := int64(0)
	high := maxEdgeCost
	ans := int64(-1)

	for low <= high {
		mid := (low + high) / 2
		dist := make([]int64, n)
		for i := 0; i < n; i++ {
			dist[i] = math.MaxInt64
		}
		dist[0] = 0

		for _, u := range topologicalOrder {
			if !online[u] {
				continue
			}
			for _, edge := range adj[u] {
				v := edge[0]
				cost := edge[1]
				if online[v] && cost >= mid {
					if dist[u]+cost < dist[v] {
						dist[v] = dist[u] + cost
					}
				}
			}
		}

		if dist[n-1] <= k {
			ans = mid
			low = mid + 1
		} else {
			high = mid - 1
		}
	}

	return ans
}
